<script>
import {mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
export default {
    components: {
        mdbInput, mdbBtn, mdbIcon,
    },
    data() {
        return {
            ticket_id: null,
            ticket_data: null,
            invoice_list: [],
            loading: false,
            loading_invoices: false,
            show_invoice_modal: false,
            selected_invoice: null,
            showCloseModal: false,
            closing_ticket: false,
        }
    },
    async mounted () {
        this.ticket_id = this.$route.params.id;
        await this.fetchTicketData();
        await this.fetchInvoices();
    },
    methods: {
        async fetchTicketData() {
            try {
                this.loading = true;
                const res = await fetch(this.$store.state.hostname + '/TegirmonTicket/' + this.ticket_id);
                const data = await res.json();
                this.loading = false;
                
                if(res.status == 200 || res.status == 201){
                    this.ticket_data = data;
                }
                else{
                    if(this.$refs.message) {
                        this.$refs.message.error('network_ne_connect')
                    }
                }
            }
            catch{
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect')
                }
                this.loading = false;
            }
        },
        async fetchInvoices() {
            try {
                this.loading_invoices = true;
                const res = await fetch(this.$store.state.hostname + '/TegirmonInvoiceNews/getInvoicesByTicketId?ticket_id=' + this.ticket_id + '&page=0&size=1000');
                const data = await res.json();
                this.loading_invoices = false;
                
                if(res.status == 200 || res.status == 201){
                    this.invoice_list = data.items_list || [];
                }
                else{
                    if(this.$refs.message) {
                        this.$refs.message.error('network_ne_connect')
                    }
                }
            }
            catch{
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect')
                }
                this.loading_invoices = false;
            }
        },
        formatNumber(num) {
            if (!num && num !== 0) return '0';
            return parseFloat(num).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
        },
        formatPercentage(num) {
            if (!num && num !== 0) return '0';
            return parseFloat(num).toFixed(1);
        },
        getPercentageClass(percentage) {
            if (percentage >= 100) return 'percentage_complete';
            if (percentage >= 50) return 'percentage_medium';
            return 'percentage_low';
        },
        formatDate(dateString) {
            if (!dateString) return '-';
            const date = new Date(dateString);
            const day = String(date.getDate()).padStart(2, '0');
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const year = date.getFullYear();
            return `${day}-${month}-${year}`;
        },
        formatTime(dateString) {
            if (!dateString) return '';
            const date = new Date(dateString);
            const hours = String(date.getHours()).padStart(2, '0');
            const minutes = String(date.getMinutes()).padStart(2, '0');
            return `${hours}:${minutes}`;
        },
        openInvoiceModal(invoice) {
            this.selected_invoice = invoice;
            this.show_invoice_modal = true;
        },
        viewInvoiceDetail() {
            if (this.selected_invoice) {
                this.show_invoice_modal = false;
                this.$router.push('/add_last_tarozi/' + this.selected_invoice.id);
            }
        },
        viewImage(imageUrl) {
            if (this.$imageModal) {
                this.$imageModal.show(imageUrl);
            }
        },
        async closeTicket() {
            try {
                this.closing_ticket = true;
                const res = await fetch(this.$store.state.hostname + '/TegirmonTicket/close/' + this.ticket_id, {
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                    }
                });
                
                if(res.status == 200 || res.status == 204){
                    this.showCloseModal = false;
                    if(this.$refs.message) {
                        this.$refs.message.success('ticket_closed_success' || 'Билет успешно закрыт');
                    }
                    // Refresh ticket data
                    await this.fetchTicketData();
                }
                else{
                    if(this.$refs.message) {
                        this.$refs.message.error('network_ne_connect');
                    }
                }
                this.closing_ticket = false;
            }
            catch(error){
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect');
                }
                this.closing_ticket = false;
            }
        }
    },
}
</script>

